  },
  "benefits": {
    "type": "service",
    "value": "Comprehensive medical and social services via interdisciplinary team (primary care doctor, nurse, therapists, social worker, dietician, etc.), including adult day care, meals, home care, transportation, lab/X-ray, dentistry, hospital/nursing home care when needed, nutritional counseling, preventive care, home modifications, equipment; all coordinated to allow community living instead of nursing home[1][3][5]",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": [],
    "processing_time": "Initial assessment within 30 days of enrollment; care plan semi-annually thereafter[7]",
    "waitlist": null,
    "forms": [],
    "documents": []
  },
  "geography": {
    "statewide": false,
    "restrictions": "Only available in areas with PACE providers; requires living near a PACE center",
    "regional_variations": "Program not yet implemented in South Dakota; feasibility studies conducted but no active providers or service areas[7][8][10]",
    "offices_or_providers": []
  },
  "official_source": "https://dhs.sd.gov (South Dakota DHS; no specific PACE page as program not active); national: https://www.cms.gov/medicare/medicaid-coordination/about/pace[2]",
  "gotchas": [
    "PACE is not currently available in South Dakota; only in states with approved providers (SD has feasibility studies but no operational programs)[7][8][10]",
    "Must live in a designated PACE service area near a center; no statewide coverage[1][3]",
    "Becomes sole source of Medicare/Medicaid services for dually eligible enrollees; voluntary and can disenroll anytime[4]",
    "95% of participants live in community, but covers nursing home if needed[6]"
