{
  "name": "Low Income Energy Assistance Program (LIEAP)",
  "eligibility": {
    "age": null,
    "income_limits": "Gross monthly household income must be at or below 200% of the federal poverty level, based on the most recent three months of income for all household members. Households where all members receive SNAP are automatically categorically eligible. Specific annual income limits for larger households (from DSS table): 7-person: $22,514; 8-person: $23,014; 9-person: $23,514; 10-person: $24,431. Limits scale by household size but exact table for 1-6 not detailed in sources; check official DSS for current full table.[5][2]",
    "asset_limits": "No asset limit applies.[1]",
    "other_requirements": [
      "Household must be responsible for heating costs (paid directly to supplier or included in rent).",
      "Application must be signed by all household members age 18+.",
      "Funding availability affects eligibility.[3]"
    ]
  },
  "benefits": {
    "type": "financial",
    "value": "One-time supplemental payment for home heating costs, paid directly to utility or energy supplier. Exact dollar amounts vary by household income, size, fuel type, and funding; not fixed per source. Related: Cooling Assistance $1025 for eligible LIEAP recipients; ECIP for crises; Weatherization for efficiency upgrades (no fixed $).[1][2][5]",
    "varies_by": "household_size|priority_tier|region"
  },
  "application": {
    "methods": [
      "Online: https://www.sd.gov/cs?id=sc_cat_item&sys_id=a254bd6edbf7f410b2fb93d4f3961974 (Low Income Energy Assistance Application).[6]",
      "Mail: South Dakota Department of Social Services, Office of Energy Assistance, 700 Governors Drive, Pierre, SD 57501.[5]",
      "Email: Scan and send to DSSHeat@state.sd.us.[5]"
    ],
    "processing_time": "Not specified in sources; apply early as funding is limited and may close when depleted.[1]",
    "waitlist": "Possible for Weatherization due to limited funds; not specified for main LIEAP.[5]",
    "forms": [
      "Low Income Energy Assistance Application (online via SD.gov).",
      "Vendor Claim Form (online for energy suppliers).[5]"
    ],
    "documents": [
      "Proof of household income for the 3 calendar months prior to application month (for everyone in household).",
      "Proof of home heating and electric costs (bills paid to supplier or as part of rent).[5]"
    ]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None statewide, but Weatherization completed by four community action programs serving specific counties.[5]",
    "regional_variations": "Weatherization varies by county (contact local community action program); potential differences in processing or wait times by local agency/funding; heating assistance statewide via central DSS office.[1][5]",
    "offices_or_providers": [
      "Central: DSS Office of Energy Assistance, 700 Governors Drive, Pierre, SD 57501.",
      "Weatherization: Four community action programs by county (list available on DSS site).[5]"
    ]
  },
  "official_source": "https://dss.sd.gov/economicassistance/energy_weatherization_assistance.aspx[5]",
  "gotchas": [
    "Funding limited; apply early in fall/winter as applications may close when funds deplete (not year-round).[1]",
    "No cooling assistance from main LIEAP; separate Cooling program only for prior/recent LIEAP recipients paying own electric.[2]",
    "Crisis (ECIP) requires active LIEAP case plus emergency like shutoff.[2][5]",
    "Roommates sharing utility bill count as one household.[1]",
    "Weatherization needs landlord permission for renters + landlord contribution; priority to elderly/disabled/families.[5]"
  ],
  "data_shape_notes": "Income at 200% FPL with 3-month lookback; no asset test; benefits as one-time payment varying by income/size/fuel; Weatherization county-specific via 4 providers; categorical eligibility via SNAP/active LIEAP for related programs."
}

{
  "name": "Senior Health Information and Insurance Education (SHIINE)",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits; open to all Medicare beneficiaries, those approaching Medicare, and their caregivers[3][4]",
    "asset_limits": "No asset limits or tests apply[3][4]",
    "other_requirements": ["Must be a Medicare beneficiary in South Dakota, approaching Medicare eligibility, or a caregiver of someone on/approaching Medicare[3][4]"]
  },
  "benefits": {
    "type": "service",
    "value": "Free, confidential, unbiased one-on-one counseling on Medicare Parts A/B, Part D prescription drugs, Medicare Advantage (HMOs/PPOs), Medigap, long-term care insurance, Medicare Savings Programs (QMB/SLMB/QI), prescription assistance, Medicaid, other insurance/free health programs; assistance with Low Income Subsidy (LIS) enrollment, plan comparison to avoid overpaying; fraud prevention via Senior Medicare Patrol (SMP); educational outreach events, printed materials, referrals[1][5]",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: Toll-free (800) 536-8197 or 1-888-854-5321; hours 9:00am-4:30pm CT[2][7]", "Website: https://dhs.sd.gov/en/ltss/shiine or https://www.shiine.net[2][3]", "Email: caitlin.christensen@state.sd.us or region-specific like western_region@shiine.net[2][4]", "In-person or phone appointment scheduling via regional coordinators or trained volunteer counselors statewide[4][5][6]"],
    "processing_time": "Immediate counseling appointment scheduling; no formal processing as it's not an entitlement program[4]",
    "waitlist": null,
    "forms": ["No specific forms required; verbal/phone appointment suffices[4]"],
    "documents": ["None required[4]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; covers all of South Dakota[3][4]",
    "regional_variations": "Three regional coordinators oversee volunteers and events; minimum two outreach events per year at each Native American reservation per region; contact regional coordinators for local services[1][6]",
    "offices_or_providers": ["South Dakota Department of Social Services, 700 Governors Drive, Pierre SD 57501-2291 (state office); regional coordinators in three regions (Western/Central, others unspecified in sources)[2][4][6]"]
  },
  "official_source": "https://dhs.sd.gov/en/ltss/shiine",
  "gotchas": ["Not a healthcare or financial aid program—provides education/counseling only, no direct payments or medical services; volunteers cannot have active insurance licenses; not affiliated with insurance sellers[1][3][6]", "During Medicare Open Enrollment (e.g., Oct 15-Dec 7 for 2026 changes), expect higher demand for Part D/LIS help[1][6]", "Electronic data transmission must be encrypted for privacy[1]"],
  "data_shape_notes": "No income/asset/age tests—universal access for Medicare-related population; regionally coordinated volunteer network with required outreach to Native reservations; counseling-focused SHIP program, not benefits-paying"
}

{
  "name": "Meals on Wheels",
  "eligibility": {
    "age": 60,
    "income_limits": "No strict statewide income limits; programs prioritize low-income seniors and follow federal poverty guidelines in some areas (e.g., commodity meals for households at or below 150% of federal poverty level). Medicaid/SSI recipients often qualify. Suggested donations requested but no one denied for inability to pay[1][3][6].",
    "asset_limits": "Not applicable; no asset tests mentioned across programs[1][3].",
    "other_requirements": ["Homebound and unable to cook or shop independently[1][2][6][8][9]", "Spouse or dependent adult of 60+ participant may qualify regardless of age[2][3]", "Under 60 must contact Dakota at Home for separate eligibility assessment[2][8]"]
  },
  "benefits": {
    "type": "service",
    "value": "One hot nutritious home-delivered meal per weekday (Monday-Friday); congregate dining also available at sites. Suggested donation $4.25-$5.25/meal (under 60 pay full ~$6.50); private pay option $15/meal in some areas. Funded by Older Americans Act[3][6][8][9].",
    "varies_by": "region"
  },
  "application": {
    "methods": ["Call local provider (e.g., Active Generations: (605) 333-3305 or 1-833-663-9673; Dakota at Home for under 60[2][8]", "Enroll online via Dakota at Home Referral Form[2][8]", "Request brochure by mail from Meals on Wheels Western SD[3]", "Contact local senior center or Meals on Wheels provider directly[1]"],
    "processing_time": "Not specified; immediate enrollment encouraged where available[2][3].",
    "waitlist": "Limited meals available; priority for need but no explicit waitlists noted[3].",
    "forms": ["Dakota at Home Referral Form (for under 60 or general inquiries)[2][8]"],
    "documents": ["Proof of age (e.g., driver's license, birth certificate)", "Doctor’s note or medical records if disabled/under 60", "Proof of income if requested (not always required)", "Call for specifics[1]"]
  },
  "geography": {
    "statewide": false,
    "restrictions": "Administered locally through senior centers and non-profits; coverage varies by community (e.g., western SD: 64 communities; Sioux Falls, Tabor, Active Generations areas)[2][3][6][8]",
    "regional_variations": "Different providers (e.g., Meals on Wheels Western SD, Active Generations, The Center in Tabor, Valley Senior Services); suggested donations vary ($4.25-$5.25); some offer congregate dining or commodity foods[3][6][8][9].",
    "offices_or_providers": ["Meals on Wheels Western South Dakota[3]", "Meals on Wheels Sioux Falls - W. 46th Street[2]", "Active Generations (605) 333-3305[8]", "The Center, Tabor SD[6]"]
  },
  "official_source": "https://dakotaathome.sd.gov/ (Dakota at Home portal for referrals and local programs)",
  "gotchas": ["Not a single statewide program—must contact local provider; homebound status key, not just age[1][9]", "Suggested donations appreciated but no denial for non-payment; limited meals may prioritize lowest need[3]", "Under 60 requires separate Dakota at Home check, not standard Meals on Wheels[2][8]", "Varies by exact community; some areas have private pay only if slots full[3][5]"],
  "data_shape_notes": "Decentralized by region with local non-profits; no uniform income/asset test, emphasis on homebound 60+; Older Americans Act funded with donations; under 60 routed to Dakota at Home"
}

