    "processing_time": "Not specified; intake screening first, then attorney referral if eligible.",
    "waitlist": "Subject to staff/volunteer availability and program resources; no formal waitlist details.",
    "forms": ["Online intake application via sdlawhelp.org/apply; complete application required prior to assistance (ERLS)"],
    "documents": ["Proof of income (e.g., pay stubs, tax returns)", "Proof of residence", "Permanent resident card if applicable (ERLS)", "Details of legal issue/case"]
  },
  "geography": {
    "statewide": false,
    "restrictions": "Varies by provider: DPLS (western/central SD, check Areas Served), ERLS (33 eastern counties: Aurora, Beadle, Bon Homme, etc.), Access to Justice (statewide referral)",
    "regional_variations": "Different providers by region (DPLS east/west divide); eligibility exceptions and services limited by local resources/staff.",
    "offices_or_providers": ["Dakota Plains Legal Services (DPLS)", "East River Legal Services (ERLS)", "Access to Justice (A2J)", "DHS Legal Services for Vulnerable Older Adults"]
